                    ))}
                  </div>

                  {/* Performance Visualization */}
                  {project.chartData && (
                    <div className="h-24 mt-4 bg-slate-50 dark:bg-slate-900/50 rounded-lg p-2">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={project.chartData}>
                          <XAxis dataKey="name" hide />
