  return (
    <div className="absolute inset-0 z-0 opacity-40 dark:opacity-60 pointer-events-none">
      <Canvas camera={{ position: [0, 0, 12], fov: 45 }}>
        <ambientLight intensity={0.5} />
        <NeuralNetwork />
      </Canvas>
    </div>
  );
};

