                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Node: SD-CLUSTER-MAIN</span>
                </div>
                <AnimatePresence>
                  {isScaling && (
                    <motion.div 
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
