      {/* Blue "Active" LED */}
      <Sphere args={[0.03, 8, 8]} position={[-1.4, 0, 1.95]}>
        <meshBasicMaterial color="#3b82f6" opacity={0.6} transparent />
      </Sphere>
    </group>
  );
};

