        <h3 className="text-xl font-bold text-slate-900 dark:text-white leading-tight">{title}</h3>
      </div>

      <div className="space-y-6">
        {skills.map((skill, index) => {
          // Calculate mastery to be above 90%
          const mastery = 98 - (index * 0.7);

