                  <SnippetCard 
                    snippet={snippet} 
                    isFocused={activeIndex === idx || (window.innerWidth >= 768 && idx >= activeIndex && idx < activeIndex + 3)} 
                  />
                </div>
              ))}
            </motion.div>
          </div>
        </div>

        <div className="flex justify-center gap-3 mt-12">
          {CODE_SNIPPETS.map((_, idx) => (
            <button
