        <div className="space-y-8">
          {patentList.map((pub, idx) => (
            <MotionDiv
              key={idx}
              initial={{ opacity: 0, x: 20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ delay: idx * 0.15 }}
